parameters.jsCode:
// Extract fields from multi-agent response
const agentResp = $input.item.json;
const d = agentResp.decision;

if (!d || agentResp.status !== 'success') {
  // Fallback: rule-based decision if agent system failed
  const soil = $('MQTT Trigger').item.json.soil || 50;
  const rain = $('MQTT Trigger').item.json.rain || false;
  return [{ json: {
    pump: soil < 30 && !rain ? 'ON' : 'OFF',
    irrigation_duration_sec: soil < 30 && !rain ? 90 : 0,
    decision: soil < 30 && !rain ? 'IRRIGATE' : 'SKIP',
    health_score: 50,
    next_check_minutes: 10,
    reason: 'Fallback rule-based decision (agent system unavailable)',
    confidence: 0,
    risk_level: 'caution',
    ...$('MQTT Trigger').item.json
  }}];
}

const cmd = d.final_command || {};
const plan = d.irrigation_plan || {};
const health = d.crop_health || {};
const safety = d.safety_validation || {};

return [{ json: {
  pump: cmd.pump || 'OFF',
  irrigation_duration_sec: Math.min(cmd.duration_sec || 0, 180),
  decision: plan.decision || 'SKIP',
  health_score: health.health_score || 0,
  next_check_minutes: plan.next_check_minutes || 10,
  reason: cmd.explanation || plan.reasoning || 'No reason provided',
  confidence: plan.confidence || 0,
  risk_level: safety.risk_level || 'unknown',
  soil_moisture: $('MQTT Trigger').item.json.soil,
  temperature: $('MQTT Trigger').item.json.temp,
  humidity: $('MQTT Trigger').item.json.hum,
  light: $('MQTT Trigger').item.json.light,
  rain_detected: $('MQTT Trigger').item.json.rain,
  rain_expected: $('Get Weather Forecast').item.json.rain_expected
}}];
